package com.ichi2.anki.preferences

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.bytehamster.lib.preferencesearch.SearchConfiguration
import com.ichi2.anki.R
import com.ichi2.anki.RobolectricTest
import com.ichi2.testutils.getJavaFieldAsAccessible
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.hasItem
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.Robolectric

/**
 * Test to verify that backup preferences are searchable in the Settings search functionality.
 * This test addresses the bug where searching for "back" or "backup" didn't show backup options.
 */
@RunWith(AndroidJUnit4::class)
class BackupSearchTest : RobolectricTest() {

    @Test
    fun `Backup preferences XML is indexed for search`() {
        // Setup
        val preferencesActivity = getPreferencesActivity()
        val searchConfig = SearchConfiguration(preferencesActivity)
        HeaderFragment.configureSearchBar(preferencesActivity, searchConfig)

        // Get the indexed files using reflection
        val filesToIndexField = getJavaFieldAsAccessible(SearchConfiguration::class.java, "filesToIndex")
        val searchItemResIdField = getJavaFieldAsAccessible(SearchConfiguration.SearchIndexItem::class.java, "resId")

        @Suppress("UNCHECKED_CAST")
        val filesToIndex = filesToIndexField.get(searchConfig) as ArrayList<SearchConfiguration.SearchIndexItem>
        val filesResIds = filesToIndex.map {
            searchItemResIdField.get(it) as Int
        }

        // Verify that preferences_backup_limits is indexed
        assertThat(
            "preferences_backup_limits should be indexed for search",
            filesResIds,
            hasItem(R.xml.preferences_backup_limits)
        )
    }

    @Test
    fun `BackupLimitsSettingsFragment has correct preference resource`() {
        // Create the fragment
        val fragment = BackupLimitsSettingsFragment()

        // Verify it points to the correct preference resource
        assertThat(
            "BackupLimitsSettingsFragment should reference preferences_backup_limits",
            fragment.preferenceResource,
            org.hamcrest.Matchers.equalTo(R.xml.preferences_backup_limits)
        )
    }

    private fun getPreferencesActivity(): Preferences {
        return Robolectric.buildActivity(Preferences::class.java)
            .create().start().resume().get()
    }
}
"}

